user_prompt:
MODE: refine

QUESTION:
What was the result of the game?

OPTIONS:
[
  "A. The game was cancelled.",
  "B. The black team won.",
  "C. The white team won.",
  "D. The two teams tied.",
  "E. The teams were disqualified."
]

